import {
  Box,
  Button,
  FormControl,
  FormLabel,
  Input,
  Textarea,
  Heading,
  Image,
  Flex,
  Text,
} from "@chakra-ui/react";
import React, { useState } from "react";
import TeacherNavTop from "./TeacherNavTop";
import { useDispatch } from "react-redux";
import { useNavigate, useLocation } from "react-router-dom";
import { addVideo } from "../../Redux/TeacherReducer/action";

const AddTeacherVideos = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();

  const { id, title } = location.state;

  const [detail, setDetail] = useState({
    title: title,
    description: "",
    link: "",
    views: "",
    img: "",
    courseId: id,
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = () => {
    if (!detail.link || !detail.title) {
      return alert("Please fill required fields");
    }

    dispatch(addVideo(detail, detail.courseId));
    alert("Video Added Successfully");
    navigate("/Teacher/add");
  };

  return (
    <>
      <TeacherNavTop />

      <Flex bg="#f7f9fa" minH="100vh" justify="center" align="center" p={5}>
        <Box
          bg="white"
          p={8}
          borderRadius="lg"
          boxShadow="lg"
          w="100%"
          maxW="600px"
        >
          {/* TITLE */}
          <Heading size="lg" mb={6}>
            Add Video
          </Heading>

          <Text mb={4} fontSize="sm" color="gray.500">
            Course: <b>{title}</b>
          </Text>

          {/* TITLE */}
          <FormControl mb={4}>
            <FormLabel>Video Title</FormLabel>
            <Input
              name="title"
              value={detail.title}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* DESCRIPTION */}
          <FormControl mb={4}>
            <FormLabel>Description</FormLabel>
            <Textarea
              name="description"
              value={detail.description}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* VIDEO LINK */}
          <FormControl mb={4}>
            <FormLabel>Video URL</FormLabel>
            <Input
              placeholder="YouTube / hosted video link"
              name="link"
              value={detail.link}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* VIEWS */}
          <FormControl mb={4}>
            <FormLabel>Views</FormLabel>
            <Input
              type="number"
              name="views"
              value={detail.views}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* THUMBNAIL */}
          <FormControl mb={4}>
            <FormLabel>Thumbnail URL</FormLabel>
            <Input
              name="img"
              value={detail.img}
              onChange={handleChange}
              _focus={{ borderColor: "#A435F0" }}
            />
          </FormControl>

          {/* PREVIEW */}
          {detail.img && (
            <Box mb={4}>
              <Text fontSize="sm" mb={2} color="gray.600">
                Thumbnail Preview
              </Text>
              <Image
                src={detail.img}
                borderRadius="md"
                maxH="180px"
                objectFit="cover"
              />
            </Box>
          )}

          {/* VIDEO PREVIEW (basic) */}
          {detail.link && (
            <Box mb={4}>
              <Text fontSize="sm" mb={2} color="gray.600">
                Video Preview
              </Text>
              <Box
                borderRadius="md"
                overflow="hidden"
                border="1px solid #e5e7eb"
              >
                <iframe
                  width="100%"
                  height="200"
                  src={detail.link}
                  title="preview"
                />
              </Box>
            </Box>
          )}

          {/* BUTTON */}
          <Button
            bg="#A435F0"
            color="white"
            w="100%"
            size="lg"
            _hover={{ bg: "#8710d8" }}
            onClick={handleSubmit}
          >
            Add Video
          </Button>
        </Box>
      </Flex>
    </>
  );
};

export default AddTeacherVideos;
